  else  reg_ms_flag <= 0;
end
//ms �����������Ƶ�1000ms ʱ���㣬Ҳ����1����
always @(posedge clk or negedge reset)
begin
  if (~reset)
     reg_ms_count <= 0;
  else  if( reg_ms_count == 999) reg_ms_count <= 10'h000;
  else  if( reg_ms_flag) reg_ms_count <= reg_ms_count + 1;
end

//����1s ��־reg_1s_flag
